={
  "blocks": [
    {
      "type": "header",
      "text": {
        "type": "plain_text",
        "text": "🟢 Positive Reply — ALIF Campaign",
        "emoji": true
      }
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Name:*\n{{ $json[\"first_name\"] }} {{ $json[\"last_name\"] }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Company:*\n{{ $json[\"company_name\"] }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Email:*\n{{ $json[\"from_address\"] }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Campaign:*\n{{ $json[\"campaign_name\"] }}"
        }
      ]
    },
    {
      "type": "divider"
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*Their reply:*\n> {{ $json[\"reply_text\"] }}"
      }
    },
    {
      "type": "actions",
      "elements": [
        {
          "type": "button",
          "text": { "type": "plain_text", "text": "View in Instantly ↗", "emoji": true },
          "style": "primary",
          "url": "https://app.instantly.ai/app/leads"
        }
      ]
    }
  ]
}

={
  "blocks": [
    {
      "type": "header",
